const items = $input.all();

const toStr = (v) => (v == null ? '' : String(v).trim());

const collectPrompts = () => {
  const out = [];
  for (const it of items) {
    const j = it.json || {};
    const arr = j?.output?.text;
    if (Array.isArray(arr)) {
      for (const s of arr) {
        const t = toStr(s);
        if (t) out.push(t);
      }
    }
    const t1 = toStr(j.text);
    if (t1) out.push(t1);
    const t2 = toStr(j.content);
    if (t2) out.push(t2);
  }
  return Array.from(new Set(out));
};

const getChatFilesBinary = () => {
  try {
    const n = $('When chat message received').first();
    const bin = n?.binary || {};
    const keys = Object.keys(bin);
    return keys.map((key) => ({ key, data: bin[key] })).filter(x => x.data);
  } catch (_) {
    return [];
  }
};

const prompts = collectPrompts();
const files = getChatFilesBinary();

if (files.length) {
  return files.map(f => ({
    json: {
      prompts,
      fileName: f.data.fileName || f.key,
      mimeType: f.data.mimeType || ''
    },
    binary: { [f.key]: f.data }
  }));
}

return [{ json: { prompts } }];

