// 获取 Gemini API 节点输出的内容
// Gemini 的层级是 candidates -> [0] -> content -> parts -> [0] -> text
const response = $input.first().json;

try {
  // 按照 Gemini 的标准路径提取文本
  const fullContent = response.candidates[0].content.parts[0].text;

  // 清洗数据：去除 AI 可能会自发生成的加粗符号 ** 或引号 "
  // 增加正则匹配，同时处理可能出现的 markdown 代码块标识 ```
  const cleanPrompt = fullContent
    .replace(/\*\*|#|"/g, '')      // 去除加粗、标题符号和引号
    .replace(/```[a-z]*\n?/gi, '') // 去除 markdown 代码块头部
    .replace(/```/g, '')           // 去除 markdown 代码块尾部
    .trim();

  return {
    json: {
      final_prompt: cleanPrompt,
      original_length: fullContent.length,
      status: "success"
    }
  };
} catch (e) {
  // 如果路径提取失败，返回原始数据以便调试
  return {
    json: {
      error: "数据路径不匹配，请检查输入",
      received_data: response,
      status: "failed"
    }
  };
}

const items = $input.all();
const outputs = [];

for (const item of items) {
  const text = item.json?.['chatInput'] || '';
  const bin = item.binary || {};

  // 获取字段名为 "22" 的图片
  const key = 'data0';
  if (bin[key]) {
    const b = bin[key];

    // 强制获取二进制 Buffer 并转为 Base64 字符串
    const buffer = await this.helpers.getBinaryDataBuffer(0, key); 
    const base64 = buffer.toString('base64');

    const mime = b.mimeType || 'image/jpeg';

    outputs.push({
      json: {
        text_11: text,
        filename: b.fileName || 'image.jpg',
        image_url_full: `data:${mime};base64,${base64}`,
      },
    });
  } else {
    outputs.push({ json: { text_11: text, image_url_full: '' } });
  }
}

return outputs;
